    pub(super) async fn read_loadbalancing_forwardingrule(
        &self,
        provider_id: &str,
    ) -> Result<ResourceOutput, ProviderError> {
        let (region, name) = super::parse_region_resource(provider_id, &self.region);
        let forwarding_rule = self
            .forwarding_rules()
            .await?
            .get()
            .set_project(&self.project_id)
            .set_region(&region)
            .set_forwarding_rule(&name)
            .send()
            .await
            .map_err(|e| super::classify_gcp_error("GetForwardingRule", e))?;

        let user_labels: serde_json::Map<String, serde_json::Value> = forwarding_rule
            .labels
            .iter()
            .filter(|(k, _)| k.as_str() != "managed_by")
            .map(|(k, v)| (k.clone(), serde_json::json!(v)))
            .collect();

        let state = serde_json::json!({
            "identity": {
                "description": forwarding_rule.description.as_deref().unwrap_or(""),
                "labels": user_labels,
                "name": forwarding_rule.name.as_deref().unwrap_or(""),
            },
            "config": {
                "all_ports": forwarding_rule.all_ports.unwrap_or(false),
                "allow_global_access": forwarding_rule.allow_global_access.unwrap_or(false),
                "allow_psc_global_access": forwarding_rule.allow_psc_global_access.unwrap_or(false),
                "backend_service": forwarding_rule.backend_service.as_deref().unwrap_or(""),
                "external_managed_backend_bucket_migration_state": &forwarding_rule.external_managed_backend_bucket_migration_state,
                "external_managed_backend_bucket_migration_testing_percentage": forwarding_rule.external_managed_backend_bucket_migration_testing_percentage.unwrap_or(0.0),
                "ip_collection": forwarding_rule.ip_collection.as_deref().unwrap_or(""),
                "ip_protocol": &forwarding_rule.ip_protocol,
                "ip_version": &forwarding_rule.ip_version,
                "is_mirroring_collector": forwarding_rule.is_mirroring_collector.unwrap_or(false),
                "metadata_filters": &forwarding_rule.metadata_filters,
                "network_tier": &forwarding_rule.network_tier,
                "no_automate_dns_zone": forwarding_rule.no_automate_dns_zone.unwrap_or(false),
                "port_range": forwarding_rule.port_range.as_deref().unwrap_or(""),
                "ports": &forwarding_rule.ports,
                "service_label": forwarding_rule.service_label.as_deref().unwrap_or(""),
                "source_ip_ranges": &forwarding_rule.source_ip_ranges,
                "target": forwarding_rule.target.as_deref().unwrap_or(""),
            },
            "network": {
                "ip_address": forwarding_rule.ip_address.as_deref().unwrap_or(""),
                "network": forwarding_rule.network.as_deref().unwrap_or(""),
                "subnetwork": forwarding_rule.subnetwork.as_deref().unwrap_or(""),
            },
        });

        let mut outputs = HashMap::new();
        outputs.insert(
            "self_link".into(),
            serde_json::json!(forwarding_rule.self_link.as_deref().unwrap_or("")),
        );

        Ok(ResourceOutput {
            provider_id: provider_id.to_string(),
            state,
            outputs,
        })
    }

